import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface CalendarData {
  todayDate: string;
  eventsCount: number;
  nextEvent: {
    title: string;
    time: string;
    location: string;
  };
}

export default function Widget() {
  const { todayDate, eventsCount, nextEvent } = response.data as CalendarData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 300, maxWidth: 380, bgcolor: '#1E1E1E', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FFC107' }}>
              Today's Date
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ my: 0.5 }}>
              {todayDate}
            </Typography>
            <Chip label={`${eventsCount} events today`} sx={{ bgcolor: '#FF5722', color: '#FFFFFF', fontSize: '12px' }} />
          </Box>

          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FFC107' }}>
              Next Event
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              <strong>Title:</strong> {nextEvent.title}
            </Typography>
            <Typography variant="body2" sx={{ mt: 0.5, color: '#FFFFFF' }}>
              <strong>Time:</strong> {nextEvent.time}
            </Typography>
            <Typography variant="body2" sx={{ mt: 0.5, color: '#FFFFFF' }}>
              <strong>Location:</strong> {nextEvent.location}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
